const body = $input.first().json.body;
if (!body || !body.dispatch_id) {
  throw new Error('Missing dispatch_id in webhook body');
}
return [{ json: { dispatch_id: body.dispatch_id } }];

const dispatch = $('Claim Dispatch Atomic').first().json || {};
const PROMPTS = {
  health_monitor: 'Eres Cathedral Health Diagnose Agent. Recibirás un incident detectado por monitoring pasivo Cathedral (disco, pdf2img, n8n exec errors, health endpoint). Devuelve SOLO JSON estricto: { "diagnosis": "texto", "proposed_fix": "texto", "confidence": 0.0-1.0, "severity": "low|medium|critical" }. NUNCA auto-aplica fix. David aprueba manual.',
  bug_diagnose: 'Eres Cathedral Bug Diagnose Agent. Recibirás un spike de errores n8n workflow (exceptions_log). Payload: total_1h, top_cluster (source+ai_guess+count), samples (5 raw excerpts recientes). Tu trabajo: (1) identificar patrón causa-raíz concreto (workflow nodo, problema upstream); (2) proponer fix técnico específico NO genérico; (3) confidence honesto 0.9 solo patrón clarísimo. Devuelve SOLO JSON estricto: { "diagnosis": "texto", "proposed_fix": "texto", "confidence": 0.0-1.0, "severity": "low|medium|critical", "root_cause_category": "n8n_node_bug | upstream_service | data_pattern | infrastructure | unknown" }. NUNCA auto-aplica.',
  pre_deploy_validator: 'Eres Cathedral Pre-Deploy Validator Agent. Stub futuro S2.',
  project_classifier: 'Eres Cathedral Project Classifier Agent. Stub futuro S3.',
  director: 'Eres Cathedral Director Agent. Stub futuro Fase 3.',
  slo_monitor: 'Eres Cathedral SLO Monitor Agent. Stub futuro.'
};
const systemPrompt = PROMPTS[dispatch.agent_name];
if (!systemPrompt) {
  throw new Error(`Unknown agent_name: ${dispatch.agent_name}`);
}
return [{ json: { ...dispatch, system_prompt: systemPrompt } }];

const resp = $input.first().json;
let text = resp.content?.[0]?.text || '{}';
text = text.replace(/^```(?:json)?\s*/, '').replace(/```\s*$/, '').trim();
let parsed = {};
try { parsed = JSON.parse(text); } catch (e) { parsed = { diagnosis: text.slice(0, 500), parse_failed: true }; }
const inputTokens = resp.usage?.input_tokens || 0;
const outputTokens = resp.usage?.output_tokens || 0;
const costUsd = (inputTokens / 1e6 * 1.0) + (outputTokens / 1e6 * 5.0);
const dispatch = $('Claim Dispatch Atomic').first().json || {};
// Extract extra fields beyond standard (diagnosis/proposed_fix/confidence/severity)
const STANDARD = new Set(['diagnosis','proposed_fix','confidence','severity']);
const extra = {};
for (const k of Object.keys(parsed)) {
  if (!STANDARD.has(k)) extra[k] = parsed[k];
}
return [{
  json: {
    dispatch_id: dispatch.id,
    agent_name: dispatch.agent_name,
    diagnosis: (parsed.diagnosis || 'unknown').slice(0, 4000),
    proposed_fix: parsed.proposed_fix ? String(parsed.proposed_fix).slice(0, 2000) : null,
    confidence: typeof parsed.confidence === 'number' ? parsed.confidence : null,
    severity: parsed.severity || dispatch.severity,
    tokens_used: inputTokens + outputTokens,
    cost_usd: Math.round(costUsd * 100000) / 100000,
    extra_context: extra
  }
}];
